161	// sortArtifacts orders artifacts by the requested sort key with a stable
162	// (sortKey, id) tie-breaker so cursor pagination is deterministic across
163	// pages even when the primary key has duplicate values.
164	func sortArtifacts(artifacts []*Artifact, key *ArtifactSort) {
165		k := ArtifactSortPath
166		if key != nil {
167			k = *key
168		}
169		sort.SliceStable(artifacts, func(i, j int) bool {
170			a, b := artifacts[i], artifacts[j]
171			var less, equal bool
172			switch k {
173			case ArtifactSortID:
174				less, equal = a.ID < b.ID, a.ID == b.ID
175			case ArtifactSortTitle:
176				less, equal = a.Title < b.Title, a.Title == b.Title
177			case ArtifactSortModified:
178				ai, bi := "", ""
179				if a.UpdatedAt != nil {
180					ai = *a.UpdatedAt
181				}
182				if b.UpdatedAt != nil {
183					bi = *b.UpdatedAt
184				}
185				less, equal = ai < bi, ai == bi
186			case ArtifactSortDepsCount:
187				ac, bc := dependsOnCount(a), dependsOnCount(b)
188				less, equal = ac < bc, ac == bc
189			default: // PATH
190				less, equal = a.Path < b.Path, a.Path == b.Path
191			}
192			if equal {
193				return a.ID < b.ID
194			}
195			return less
196		})
197	}
