199	// dependsOnCount returns the number of depends_on entries declared in the
200	// artifact's frontmatter, or 0 if none / unparseable.
201	func dependsOnCount(a *Artifact) int {
202		if a.DdxFrontmatter == nil {
203			return 0
204		}
205		var fm map[string]interface{}
206		if err := json.Unmarshal([]byte(*a.DdxFrontmatter), &fm); err != nil {
207			return 0
208		}
209		deps, ok := fm["depends_on"].([]interface{})
210		if !ok {
211			return 0
212		}
213		return len(deps)
214	}
