235	// collectDocArtifacts builds Artifact records from the FEAT-007 doc graph.
236	func collectDocArtifacts(root string) ([]*Artifact, error) {
237		graph, err := docgraph.BuildGraphWithConfig(root)
238		if err != nil {
239			return nil, err
240		}
241	
242		staleSet := map[string]string{} // id → staleness ("stale" or "missing")
243		for _, entry := range graph.StaleDocs() {
244			staleness := "stale"
245			for _, reason := range entry.Reasons {
246				if strings.Contains(reason, "missing dependency") ||
247					strings.Contains(reason, "missing review hash") {
248					staleness = "missing"
249					break
250				}
251			}
252			staleSet[entry.ID] = staleness
253		}
254	
255		docs := graph.AllNodesForOutput()
256		out := make([]*Artifact, 0, len(docs))
257		for _, d := range docs {
258			staleness := "fresh"
259			if s, ok := staleSet[d.ID]; ok {
260				staleness = s
261			}
262	
263			a := &Artifact{
264				ID:        "doc:" + d.ID,
265				Path:      d.Path,
266				Title:     titleFromDoc(d),
267				MediaType: "text/markdown",
268				Staleness: staleness,
269			}
270	
271			// Populate updatedAt from file mod time.
272			absPath := d.Path
273			if !filepath.IsAbs(absPath) {
274				absPath = filepath.Join(graph.RootDir, absPath)
275			}
276			if info, statErr := os.Stat(absPath); statErr == nil {
277				ts := info.ModTime().UTC().Format(time.RFC3339)
278				a.UpdatedAt = &ts
279			}
280	
281			// Populate ddxFrontmatter as a JSON summary of available metadata.
282			frontmatter := map[string]interface{}{
283				"id": d.ID,
284			}
285			if len(d.DependsOn) > 0 {
286				frontmatter["depends_on"] = d.DependsOn
287			}
288			if d.Prompt != "" {
289				frontmatter["prompt"] = d.Prompt
290			}
291			if fm, err := json.Marshal(frontmatter); err == nil {
292				s := string(fm)
293				a.DdxFrontmatter = &s
294			}
295	
296			out = append(out, a)
297		}
298		return out, nil
299	}
