431	// titleFromDoc derives a human-readable title from a docgraph document.
432	// Uses the Title field if set, otherwise derives from the path's base name.
433	func titleFromDoc(d docgraph.Document) string {
434		if d.Title != "" {
435			return d.Title
436		}
437		base := filepath.Base(d.Path)
438		// Strip extension.
439		if idx := strings.LastIndex(base, "."); idx > 0 {
440			base = base[:idx]
441		}
442		return base
443	}
